'use client';

import React, { useMemo, useState } from 'react';
import { useDevContext } from './DevProvider';
// Note: CSS is provided by consumer via `import '@process.co/ui/styles'`

/**
 * Helper: get slots from data when the shape is { cases: { cases: [...] } } or similar.
 * Use this inside slotConfig.getSlots for Switch-style data, or implement your own for other shapes.
 */
export function getSlotsFromCasesData(data: Record<string, any>): { id: string; label: string }[] {
  const list = data?.cases?.cases ?? data?.cases ?? data?.branches;
  if (!Array.isArray(list)) return [];
  return list.map((item: any) => ({
    id: item.id ?? String(item),
    label: item.label ?? item.id ?? String(item),
  }));
}

/**
 * DevToolbar - Optional toolbar for development
 * Shows current data state and provides controls for import/export/clear
 * Also allows spoofing inferred types and selecting active path/case when slotConfig.getSlots is provided
 */
export function DevToolbar({ className }: { className?: string }) {
  const devCtx = useDevContext();
  const [showData, setShowData] = useState(false);
  const [showDefinition, setShowDefinition] = useState(false);
  const [showTypeEditor, setShowTypeEditor] = useState(false);
  const [newTypeKey, setNewTypeKey] = useState('');
  const [newTypeValue, setNewTypeValue] = useState('');
  
  const slots = useMemo(() => {
    if (!devCtx?.slotConfig?.getSlots) return [];
    const data = devCtx.data ?? {};
    return devCtx.slotConfig.getSlots(data);
  }, [devCtx?.slotConfig, devCtx?.data]);
  
  if (!devCtx) {
    return <div className={className}>DevToolbar: Not inside DevProvider</div>;
  }

  const handleAddType = () => {
    if (newTypeKey.trim() && newTypeValue.trim()) {
      devCtx.setInferredType(newTypeKey.trim(), newTypeValue.trim());
      setNewTypeKey('');
      setNewTypeValue('');
    }
  };

  const handleRemoveType = (key: string) => {
    devCtx.clearInferredType(key);
  };

  const handleClearAllTypes = () => {
    if (confirm('Clear all inferred types?')) {
      devCtx.clearAllInferredTypes();
    }
  };
  
  return (
    <div className={`${className || ''} uii:border uii:rounded-lg uii:p-4 uii:bg-gray-50 dark:uii:bg-gray-900`}>
      <div className="uii:flex uii:items-center uii:gap-4 uii:mb-2 uii:flex-wrap">
        <span className="uii:font-semibold uii:text-sm ">🛠️ Dev Mode</span>
        <span className="uii:text-xs uii:text-gray-500">Node: {devCtx.nodeId}</span>
        <button 
          onClick={() => setShowData(!showData)}
          className="uii:text-xs uii:px-2 uii:py-1 uii:bg-blue-100 dark:uii:bg-blue-900 uii:rounded hover:uii:bg-blue-200"
        >
          {showData ? 'Hide' : 'Show'} Data
        </button>
        <button 
          onClick={() => setShowDefinition(!showDefinition)}
          className="uii:text-xs uii:px-2 uii:py-1 uii:bg-amber-100 dark:uii:bg-amber-900 uii:rounded hover:uii:bg-amber-200"
        >
          {showDefinition ? 'Hide' : 'Show'} Definition
        </button>
        <button 
          onClick={() => setShowTypeEditor(!showTypeEditor)}
          className="uii:text-xs uii:px-2 uii:py-1 uii:bg-purple-100 dark:uii:bg-purple-900 uii:rounded hover:uii:bg-purple-200"
        >
          {showTypeEditor ? 'Hide' : 'Spoof'} Types
        </button>
        <button 
          onClick={() => {
            const json = devCtx.exportData();
            navigator.clipboard.writeText(json);
            alert('Data copied to clipboard!');
          }}
          className="uii:text-xs uii:px-2 uii:py-1 uii:bg-green-100 dark:uii:bg-green-900 uii:rounded hover:uii:bg-green-200"
        >
          Export
        </button>
        <button 
          onClick={() => {
            const json = prompt('Paste JSON data:');
            if (json) devCtx.importData(json);
          }}
          className="uii:text-xs uii:px-2 uii:py-1 uii:bg-yellow-100 dark:uii:bg-yellow-900 uii:rounded hover:uii:bg-yellow-200"
        >
          Import
        </button>
        <button 
          onClick={() => {
            if (confirm('Clear all data?')) devCtx.clearAll();
          }}
          className="uii:text-xs uii:px-2 uii:py-1 uii:bg-red-100 dark:uii:bg-red-900 uii:rounded hover:uii:bg-red-200"
        >
          Clear
        </button>
      </div>

      {/* Active path/case selector when slotConfig.getSlots is provided */}
      {slots.length > 0 && (
        <div className="uii:mt-2 uii:p-2 uii:bg-slate-50 dark:uii:bg-slate-900 uii:rounded-lg uii:border uii:border-slate-200 dark:uii:border-slate-700">
          <div className="uii:text-xs uii:font-medium uii:mb-1.5 uii:text-slate-600 dark:uii:text-slate-400">
            Active path / case
          </div>
          <div className="uii:flex uii:flex-wrap uii:gap-1">
            <button
              type="button"
              onClick={() => devCtx.setActiveSlotId(null)}
              className={`uii:text-xs uii:px-2 uii:py-1 uii:rounded uii:border ${
                devCtx.activeSlotId === null
                  ? 'uii:bg-slate-300 dark:uii:bg-slate-600 uii:border-slate-500'
                  : 'uii:bg-slate-100 dark:uii:bg-slate-800 uii:border-slate-300 dark:uii:border-slate-600 hover:uii:bg-slate-200'
              }`}
            >
              (none)
            </button>
            {slots.map((slot) => (
              <button
                key={slot.id}
                type="button"
                onClick={() => devCtx.setActiveSlotId(slot.id)}
                className={`uii:text-xs uii:px-2 uii:py-1 uii:rounded uii:border ${
                  devCtx.activeSlotId === slot.id
                    ? 'uii:bg-blue-200 dark:uii:bg-blue-800 uii:border-blue-500'
                    : 'uii:bg-white dark:uii:bg-slate-800 uii:border-slate-300 dark:uii:border-slate-600 hover:uii:bg-slate-100 dark:uii:hover:bg-slate-700'
                }`}
              >
                {slot.label || slot.id}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Inferred Types Spoofing Section */}
      {showTypeEditor && (
        <div className="uii:mt-3 uii:p-3 uii:bg-purple-50 dark:uii:bg-purple-950 uii:rounded-lg uii:border uii:border-purple-200 dark:uii:border-purple-800">
          <div className="uii:text-xs uii:font-medium uii:mb-2 uii:text-purple-700 dark:uii:text-purple-300">
            Spoof Inferred Types (simulate external field types)
          </div>
          
          {/* Add new type */}
          <div className="uii:flex uii:gap-2 uii:mb-2 uii:flex-wrap">
            <input
              type="text"
              placeholder="Field name (e.g., switchExpression)"
              value={newTypeKey}
              onChange={(e) => setNewTypeKey(e.target.value)}
              className="uii:text-xs uii:px-2 uii:py-1 uii:border uii:rounded uii:flex-1 uii:min-w-[150px] uii:bg-white dark:uii:bg-gray-800"
            />
            <input
              type="text"
              placeholder="Type (e.g., string | number)"
              value={newTypeValue}
              onChange={(e) => setNewTypeValue(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAddType()}
              className="uii:text-xs uii:px-2 uii:py-1 uii:border uii:rounded uii:flex-1 uii:min-w-[200px] uii:bg-white dark:uii:bg-gray-800"
            />
            <button
              onClick={handleAddType}
              disabled={!newTypeKey.trim() || !newTypeValue.trim()}
              className="uii:text-xs uii:px-3 uii:py-1 uii:bg-purple-500 uii:text-white uii:rounded hover:uii:bg-purple-600 disabled:uii:opacity-50 disabled:uii:cursor-not-allowed"
            >
              Add
            </button>
          </div>

          {/* Current inferred types */}
          {Object.keys(devCtx.inferredTypes).length > 0 && (
            <div className="uii:mt-2">
              <div className="uii:flex uii:items-center uii:justify-between uii:mb-1">
                <span className="uii:text-xs uii:text-gray-500">Current inferred types:</span>
                <button
                  onClick={handleClearAllTypes}
                  className="uii:text-xs uii:px-2 uii:py-0.5 uii:bg-red-100 dark:uii:bg-red-900 uii:text-red-700 dark:uii:text-red-300 uii:rounded hover:uii:bg-red-200"
                >
                  Clear All
                </button>
              </div>
              <div className="uii:space-y-1">
                {Object.entries(devCtx.inferredTypes).map(([key, value]) => (
                  value && (
                    <div 
                      key={key}
                      className="uii:flex uii:items-center uii:gap-2 uii:text-xs uii:bg-white dark:uii:bg-gray-800 uii:px-2 uii:py-1 uii:rounded"
                    >
                      <button
                        onClick={() => {
                          navigator.clipboard.writeText(key);
                        }}
                        className="uii:text-gray-400 hover:uii:text-purple-600 uii:text-xs"
                        title="Copy field name"
                      >
                        📋
                      </button>
                      <span 
                        className="uii:font-mono uii:text-purple-600 dark:uii:text-purple-400 uii:cursor-pointer uii:truncate uii:max-w-[300px]"
                        onClick={() => {
                          navigator.clipboard.writeText(key);
                        }}
                        title={key}
                      >
                        {key}
                      </span>
                      <span className="uii:text-gray-400">→</span>
                      <span className="uii:font-mono uii:text-gray-600 dark:uii:text-gray-300 uii:flex-1 uii:truncate">{value}</span>
                      <button
                        onClick={() => handleRemoveType(key)}
                        className="uii:text-red-500 hover:uii:text-red-700 uii:text-xs"
                        title="Remove"
                      >
                        ✕
                      </button>
                    </div>
                  )
                ))}
              </div>
            </div>
          )}
        </div>
      )}
      
      {showData && (
        <div className="uii:mt-2">
          <div className="uii:text-xs uii:mb-1 uii:font-medium">Data:</div>
          <pre className="uii:text-xs uii:bg-gray-100 dark:uii:bg-gray-800 uii:p-2 uii:rounded uii:overflow-auto uii:max-h-48">
            {JSON.stringify(devCtx.data, null, 2)}
          </pre>
          <div className="uii:text-xs uii:mb-1 uii:mt-2 uii:font-medium">Inferred Types:</div>
          <pre className="uii:text-xs uii:bg-gray-100 dark:uii:bg-gray-800 uii:p-2 uii:rounded uii:overflow-auto uii:max-h-24">
            {JSON.stringify(devCtx.inferredTypes, null, 2)}
          </pre>
        </div>
      )}

      {showDefinition && (
        <div className="uii:mt-2">
          <div className="uii:text-xs uii:mb-1 uii:font-medium">Action / signal definition:</div>
          {devCtx.elementDefinition != null ? (
            <pre className="uii:text-xs uii:bg-amber-50 dark:uii:bg-amber-950/30 uii:p-2 uii:rounded uii:overflow-auto uii:max-h-64 uii:border uii:border-amber-200 dark:uii:border-amber-800">
              {JSON.stringify(devCtx.elementDefinition, null, 2)}
            </pre>
          ) : (
            <p className="uii:text-xs uii:text-gray-500 uii:italic">No definition passed to DevProvider.</p>
          )}
        </div>
      )}
    </div>
  );
}

export default DevToolbar;
