'use client';

import React, { createContext, useContext, useState, useCallback, useEffect, useMemo, type PropsWithChildren } from 'react';

// ============================================================================
// Types
// ============================================================================

/**
 * Optional config for slot/case awareness in dev.
 * Each control type can have unique data shape; getSlots interprets the field value and returns slot options.
 */
export interface DevSlotConfig {
  /** Property key (field) whose value holds the slot data (e.g. 'switchValue' or 'cases'). When set, getSlots and activeIdPath are applied to data[field]. */
  field?: string;
  /** Path (relative to the field value when field is set) where we store the active slot id in dev. This is mocked in dev only; we do not use the element definition's slots.activeSlotId (e.g. $.results.pathId). */
  activeIdPath: string;
  /**
   * Given the field value (or full data when field is unset), return the list of slots for the Active path/case selector.
   * Enables any control-specific shape (e.g. value.cases.cases, value.branches, etc.).
   */
  getSlots: (fieldValueOrData: Record<string, any>) => { id: string; label: string }[];
}

/** Preset for slot/case awareness (legacy); prefer deriving from elementDefinition.slots. */
export type SlotPreset = 'switch' | 'cases' | 'branches';

// ---------- Path evaluation (match layout.ts semantics for $.data.xxx paths) ----------
// Definition paths: $.data.cases.cases[*] = collection of slots ([*] = ordinal index).
// idPath "$.data.cases.cases[*].id" => slot i has id collection[i].id (e.g. cases.cases[0].id, cases.cases[1].id).
// In dev, $.data === data[propertyKey] (e.g. devField); flat shape devField.cases is supported via fallback.
function evaluateSimplePath(obj: any, path: string): any {
  if (!path || !obj) return undefined;
  const cleanPath = path.startsWith('$.') ? path.slice(2) : path.startsWith('$') ? path.slice(1) : path;
  const parts = cleanPath.split('.');
  let current = obj.data ?? obj;
  for (const part of parts) {
    if (current == null) return undefined;
    const cleanPart = part.replace(/\[\*\]$/, '');
    if (cleanPart) current = current[cleanPart];
  }
  return current;
}

function evaluateCollectionPath(obj: any, path: string): any[] {
  if (!path || !obj) return [];
  let cleanPath = path.startsWith('$.') ? path.slice(2) : path.startsWith('$') ? path.slice(1) : path;
  cleanPath = cleanPath.replace(/\[\*\]$/, '');
  const parts = cleanPath.split('.');
  let current = obj.data ?? obj;
  for (const part of parts) {
    if (current == null) return [];
    if (part) current = current[part];
  }
  if (Array.isArray(current)) return current;
  // Fallback: definition may say .cases.cases[*] but dev data has .cases as the array (flat shape).
  // Navigate from obj (root) so "data.cases" yields obj.data.cases, not obj.data["data"].
  if (parts.length >= 2) {
    const parentPath = parts.slice(0, -1).join('.');
    let parent: any = obj;
    for (const part of parentPath.split('.')) {
      if (parent == null) return [];
      if (part) parent = parent[part];
    }
    if (Array.isArray(parent)) return parent;
  }
  return [];
}

function evaluateItemPath(item: any, fullPath: string, _index: number): any {
  if (!fullPath || item == null) return undefined;
  const wildcardIndex = fullPath.indexOf('[*]');
  if (wildcardIndex === -1) return evaluateSimplePath(item, fullPath);
  const afterWildcard = fullPath.slice(wildcardIndex + 3);
  if (!afterWildcard || afterWildcard === '') return item;
  const propertyPath = afterWildcard.startsWith('.') ? afterWildcard.slice(1) : afterWildcard;
  const parts = propertyPath.split('.');
  let current = item;
  for (const part of parts) {
    if (current == null) return undefined;
    current = current[part];
  }
  return current;
}

/** Extract property name from slot paths (e.g. $.data.cases.cases[*] -> "cases"). Matches the prop that has the UI (e.g. cases with ui.switch). */
function deriveFieldFromSlotsDefinition(slotsConfig: any[]): string | undefined {
  for (const slot of slotsConfig) {
    const path = slot.path ?? slot.idPath ?? slot.labelPath;
    if (typeof path !== 'string') continue;
    const afterData = path.replace(/^\$\.data\./, '').replace(/^\$\./, '');
    const firstSegment = afterData.split('.')[0];
    if (firstSegment) return firstSegment;
  }
  return undefined;
}

/** From definition props, get the key of the prop that has the given UI (e.g. "ui.switch") or that matches the slots field. */
function deriveControlPropertyKey(
  def: ElementDefinition | null | undefined,
  slotsField: string | undefined
): string | undefined {
  const props = def?.props;
  if (!props) return slotsField;
  const arr = Array.isArray(props) ? props : Object.keys(props).map((k) => ({ key: k, ...(props as any)[k] }));
  const withUi = arr.find((p: any) => p?.ui != null);
  const matchKey = slotsField ? arr.find((p: any) => p?.key === slotsField) : withUi;
  return (matchKey?.key ?? withUi?.key ?? slotsField) as string | undefined;
}

/**
 * Action/signal definition shape (defineAction): optional slots, initValue, props.
 * Used to derive slotConfig and optionally initialData.
 */
export interface ElementDefinition {
  slots?: { slots?: any[]; activeSlotId?: string; [k: string]: any };
  initValue?: Record<string, any>;
  props?: Record<string, any>;
  [k: string]: any;
}

function isDynamicSlot(slot: any): boolean {
  if (slot.type === 'dynamic') return true;
  const path = slot.path ?? slot.idPath ?? slot.labelPath ?? '';
  return typeof path === 'string' && path.includes('[*]');
}

/** Normalized slot definition (static or dynamic) in definition order. */
interface SlotDefinition {
  type: 'static' | 'dynamic';
  path?: string;
  idPath?: string;
  labelPath?: string;
  id?: string;
  label?: string;
  labelPlaceholderValue?: string;
  [k: string]: any;
}

/** Pass 1: Derive ordered slot definitions from the definition. Preserves order (e.g. static first, dynamic middle, static default). */
function getSlotDefinitions(slotsConfig: any[]): SlotDefinition[] {
  return slotsConfig.map((slot) => ({
    ...slot,
    type: isDynamicSlot(slot) ? 'dynamic' : 'static',
  }));
}

/** Rewrite definition path when node.data = control value (e.g. devField). $.data.cases.xxx -> $.xxx so the evaluator (which starts at obj.data) only applies the rest, e.g. "cases[*]". */
function rewritePathForControlBase(path: string, definitionPropertyKey: string | undefined): string {
  if (!path || !definitionPropertyKey) return path;
  const afterData = path.replace(/^\$\.data\./, '');
  if (!afterData.startsWith(definitionPropertyKey + '.')) return path;
  const rest = afterData.slice(definitionPropertyKey.length + 1);
  return rest ? '$.' + rest : path;
}

/** Pass 2: Resolve slot definitions against current node data to build the toolbar list. */
function resolveSlotDefinitions(
  slotDefinitions: SlotDefinition[],
  node: { data: any },
  nodeIdForStatic: string,
  definitionPropertyKey: string | undefined
): { id: string; label: string }[] {
  const result: { id: string; label: string }[] = [];
  for (const slot of slotDefinitions) {
    if (slot.type === 'static') {
      const idPath = slot.idPath != null ? rewritePathForControlBase(slot.idPath, definitionPropertyKey) : undefined;
      const id =
        idPath != null
          ? evaluateSimplePath(node, idPath)
          : slot.id != null
            ? String(slot.id).replace(/\{\{ID_GUID\}\}/g, nodeIdForStatic)
            : undefined;
      const labelPath = slot.labelPath != null ? rewritePathForControlBase(slot.labelPath, definitionPropertyKey) : undefined;
      const label =
        labelPath != null
          ? evaluateSimplePath(node, labelPath)
          : slot.labelPlaceholderValue ?? slot.label ?? (id ?? '');
      result.push({ id: id ?? '', label: label ?? id ?? '' });
    } else {
      const path = slot.path ?? slot.idPath;
      if (!path) continue;
      const pathRewritten = rewritePathForControlBase(path, definitionPropertyKey);
      const collection = evaluateCollectionPath(node, pathRewritten);
      if (!Array.isArray(collection)) continue;
      const idPath = rewritePathForControlBase(slot.idPath ?? path, definitionPropertyKey);
      const labelPath = rewritePathForControlBase(slot.labelPath ?? path, definitionPropertyKey);
      collection.forEach((item: any, index: number) => {
        const id = evaluateItemPath(item, idPath, index) ?? item?.id ?? String(index);
        const label = evaluateItemPath(item, labelPath, index) ?? item?.label ?? id ?? String(index);
        result.push({ id: String(id), label: String(label) });
      });
    }
  }
  return result;
}

/** Build getSlots from element definition. devPropertyKey = where control value lives in dev (e.g. devField); definitionPropertyKey = property in definition paths (e.g. cases). So devField = $.data.cases. */
function buildGetSlotsFromDefinition(
  slotDefinitions: SlotDefinition[],
  nodeIdForStatic: string,
  options: { devPropertyKey?: string; definitionPropertyKey?: string }
): (fullData: Record<string, any>) => { id: string; label: string }[] {
  const { devPropertyKey, definitionPropertyKey } = options;
  return (fullData) => {
    const controlValue =
      devPropertyKey != null && fullData != null ? fullData[devPropertyKey] : fullData;
    const node = { data: controlValue ?? {} };
    return resolveSlotDefinitions(
      slotDefinitions,
      node,
      nodeIdForStatic,
      definitionPropertyKey
    );
  };
}

function deriveSlotConfigFromDefinition(
  def: ElementDefinition | null | undefined,
  nodeId: string,
  propertyKeyFromLoader: string | undefined
): DevSlotConfig | undefined {
  const slotsRoot = def?.slots;
  const slotsConfig = Array.isArray(slotsRoot) ? slotsRoot : slotsRoot?.slots;
  if (!Array.isArray(slotsConfig) || slotsConfig.length === 0) return undefined;
  const field = deriveFieldFromSlotsDefinition(slotsConfig);
  const definitionPropertyKey = deriveControlPropertyKey(def, field);
  const devPropertyKey = propertyKeyFromLoader ?? definitionPropertyKey;
  const slotDefinitions = getSlotDefinitions(slotsConfig);
  const getSlots = buildGetSlotsFromDefinition(slotDefinitions, nodeId ?? 'dev-node', {
    devPropertyKey,
    definitionPropertyKey,
  });
  return {
    field: devPropertyKey ?? field ?? undefined,
    activeIdPath: 'activeSlotId',
    getSlots,
  };
}

/**
 * Configuration for the DevProvider
 */
export interface DevProviderConfig {
  /** Unique key for localStorage persistence (defaults to 'process-dev') */
  storageKey?: string;
  /** Initial data to populate the store */
  initialData?: Record<string, any>;
  /** Whether to persist to localStorage (default: true) */
  persist?: boolean;
  /** Mock node ID (default: 'dev-node-1') */
  nodeId?: string;

  /** Key in dev data that holds the control value (e.g. devField). In the definition, the control is the prop with the UI (e.g. cases with ui.switch); in dev that value lives at data[propertyKey], so devField = $.data.cases. Default: 'devField' */
  propertyKey?: string;
  /** When set, provider builds slotConfig internally; loader does not need to pass slotConfig. */
  slotPreset?: SlotPreset;
  /** Optional. Full slot config; overrides slotPreset and elementDefinition when provided. */
  slotConfig?: DevSlotConfig;
  /**
   * Action or signal definition (defineAction result). Provider derives slotConfig from slots + initValue
   * and uses initValue as initialData when initialData is not provided.
   */
  elementDefinition?: ElementDefinition | null;
}

/**
 * Context value for development/testing
 */
export interface DevContextValue {
  // Node property store
  data: Record<string, any>;
  setProperty: (key: string, value: any) => void;
  getProperty: <T = any>(key: string) => T | undefined;
  
  // Inferred types
  inferredTypes: Record<string, string>;
  setInferredType: (fieldName: string, type: string) => void;
  getInferredType: (fieldName: string) => string | undefined;
  /** Remove an inferred type by field name */
  clearInferredType: (fieldName: string) => void;
  /** Remove all inferred types */
  clearAllInferredTypes: () => void;
  
  // Metadata
  nodeId: string;

  /** Current active slot/case id (for elements with slots, e.g. Switch). Null when none selected. Provider state only; not stored in data. */
  activeSlotId: string | null;
  /** Set the active slot/case id. Stored in provider state only; not written to data. */
  setActiveSlotId: (id: string | null) => void;
  /** Slot config when provided to DevProvider (so toolbar can call getSlots(data)). */
  slotConfig: DevSlotConfig | undefined;
  /** Action/signal definition passed to DevProvider (for debugging). */
  elementDefinition: ElementDefinition | null | undefined;

  // Utilities
  clearAll: () => void;
  exportData: () => string;
  importData: (json: string) => void;
}

// ============================================================================
// Context
// ============================================================================

export const DevContext = createContext<DevContextValue | null>(null);

/**
 * Hook to access the dev context for property management
 */
export function useDevContext(): DevContextValue | null {
  return useContext(DevContext);
}

/**
 * Hook that mimics useNodeProperty from the real system
 * Works in both dev mode (with DevProvider) and production (with NodePropertyProvider)
 */
export function useNodeProperty<T = any>(fieldName: string): [T | undefined, (value: T) => void] {
  const devCtx = useDevContext();
  
  if (devCtx) {
    // Dev mode - use local state with persistence
    const value = devCtx.getProperty<T>(fieldName);
    const setValue = useCallback((newValue: T) => {
      devCtx.setProperty(fieldName, newValue);
    }, [devCtx, fieldName]);
    
    return [value, setValue];
  }
  
  // Not in dev mode - this is a fallback, real implementation should be provided by host
  console.warn(`useNodeProperty('${fieldName}') called outside of DevProvider - returning undefined`);
  const [localValue, setLocalValue] = useState<T | undefined>(undefined);
  return [localValue, setLocalValue];
}

/**
 * Hook that mimics useInferredTypes from the real system
 */
export function useInferredTypes() {
  const devCtx = useDevContext();
  
  if (devCtx) {
    return {
      inferredTypes: devCtx.inferredTypes,
      setInferredType: devCtx.setInferredType,
      getInferredType: devCtx.getInferredType,
    };
  }
  
  // Not in dev mode - return null (components should handle this gracefully)
  return null;
}

// ============================================================================
// Provider
// ============================================================================

/**
 * DevProvider - Development environment for testing custom UI components
 * 
 * Features:
 * - Persists data to localStorage
 * - Provides mock implementations of useNodeProperty and useInferredTypes
 * - Supports import/export of data for testing scenarios
 * 
 * Usage:
 * ```tsx
 * import { DevProvider } from '@process.co/ui/dev';
 * 
 * function App() {
 *   return (
 *     <DevProvider 
 *       storageKey="my-component-dev"
 *       initialData={{ switchValue: { cases: [] } }}
 *     >
 *       <MyCustomComponent fieldName="switchValue" />
 *     </DevProvider>
 *   );
 * }
 * ```
 */
export function DevProvider({
  children, 
  storageKey = 'process-dev',
  initialData = {},
  persist = true,
  nodeId = 'dev-node-1',
  propertyKey = 'devField',
  slotPreset,
  slotConfig: slotConfigProp,
  elementDefinition,
}: PropsWithChildren<DevProviderConfig>) {
  const slotConfig = useMemo<DevSlotConfig | undefined>(
    () =>
      slotConfigProp ??
      deriveSlotConfigFromDefinition(elementDefinition, nodeId, propertyKey),
    [slotConfigProp, elementDefinition, nodeId, propertyKey]
  );
  const effectiveInitialData = useMemo(
    () => (Object.keys(initialData).length > 0 ? initialData : elementDefinition?.initValue ?? {}),
    [initialData, elementDefinition?.initValue]
  );

  // ========== Active slot/case (for Switch-like elements) ==========
  const [activeSlotId, setActiveSlotIdState] = useState<string | null>(null);

  // ========== Property Store ==========
  const [data, setData] = useState<Record<string, any>>(() => {
    // Try to load from localStorage first
    if (persist && typeof window !== 'undefined') {
      try {
        const stored = localStorage.getItem(`${storageKey}:data`);
        if (stored) {
          return { ...effectiveInitialData, ...JSON.parse(stored) };
        }
      } catch (e) {
        console.warn('DevProvider: Failed to load from localStorage', e);
      }
    }
    return effectiveInitialData;
  });
  
  // ========== Inferred Types ==========
  const [inferredTypes, setInferredTypesState] = useState<Record<string, string>>(() => {
    if (persist && typeof window !== 'undefined') {
      try {
        const stored = localStorage.getItem(`${storageKey}:inferredTypes`);
        if (stored) {
          return JSON.parse(stored);
        }
      } catch (e) {
        console.warn('DevProvider: Failed to load inferredTypes from localStorage', e);
      }
    }
    return {};
  });
  
  // Seed data from elementDefinition.initValue when definition appears and we have no stored data
  useEffect(() => {
    if (!elementDefinition?.initValue || typeof elementDefinition.initValue !== 'object') return;
    setData((prev) => (Object.keys(prev).length === 0 ? { ...elementDefinition!.initValue } : prev));
  }, [elementDefinition?.initValue]);

  // ========== Persist to localStorage ==========
  useEffect(() => {
    if (persist && typeof window !== 'undefined') {
      try {
        localStorage.setItem(`${storageKey}:data`, JSON.stringify(data));
      } catch (e) {
        console.warn('DevProvider: Failed to save data to localStorage', e);
      }
    }
  }, [data, storageKey, persist]);
  
  useEffect(() => {
    if (persist && typeof window !== 'undefined') {
      try {
        localStorage.setItem(`${storageKey}:inferredTypes`, JSON.stringify(inferredTypes));
      } catch (e) {
        console.warn('DevProvider: Failed to save inferredTypes to localStorage', e);
      }
    }
  }, [inferredTypes, storageKey, persist]);
  
  // ========== Property Methods ==========
  const setProperty = useCallback((key: string, value: any) => {
    setData(prev => ({ ...prev, [key]: value }));
  }, []);

  // setActiveSlotId: dev-only state in the provider; not written to data (so it never appears in Data view or export)
  const setActiveSlotId = useCallback((id: string | null) => {
    setActiveSlotIdState(id);
  }, []);
  
  const getProperty = useCallback(<T = any>(key: string): T | undefined => {
    return data[key] as T | undefined;
  }, [data]);
  
  // ========== Inferred Types Methods ==========
  const setInferredType = useCallback((fieldName: string, type: string) => {
    setInferredTypesState(prev => ({ ...prev, [fieldName]: type }));
  }, []);
  
  const getInferredType = useCallback((fieldName: string): string | undefined => {
    return inferredTypes[fieldName];
  }, [inferredTypes]);
  
  const clearInferredType = useCallback((fieldName: string) => {
    setInferredTypesState(prev => {
      const { [fieldName]: _, ...rest } = prev;
      return rest;
    });
  }, []);
  
  const clearAllInferredTypes = useCallback(() => {
    setInferredTypesState({});
  }, []);
  
  // ========== Utility Methods ==========
  const clearAll = useCallback(() => {
    setData({});
    setInferredTypesState({});
    if (persist && typeof window !== 'undefined') {
      localStorage.removeItem(`${storageKey}:data`);
      localStorage.removeItem(`${storageKey}:inferredTypes`);
    }
  }, [storageKey, persist]);
  
  const exportData = useCallback(() => {
    return JSON.stringify({ data, inferredTypes }, null, 2);
  }, [data, inferredTypes]);

  const importData = useCallback((json: string) => {
    try {
      const parsed = JSON.parse(json);
      if (parsed.data) setData(parsed.data);
      if (parsed.inferredTypes) setInferredTypesState(parsed.inferredTypes);
    } catch (e) {
      console.error('DevProvider: Failed to import data', e);
    }
  }, []);
  
  // ========== Context Value ==========
  const value = useMemo<DevContextValue>(() => ({
    data,
    setProperty,
    getProperty,
    inferredTypes,
    setInferredType,
    getInferredType,
    clearInferredType,
    clearAllInferredTypes,
    nodeId,
    activeSlotId,
    setActiveSlotId,
    slotConfig,
    elementDefinition,
    clearAll,
    exportData,
    importData,
  }), [data, setProperty, getProperty, inferredTypes, setInferredType, getInferredType, clearInferredType, clearAllInferredTypes, nodeId, activeSlotId, setActiveSlotId, slotConfig, elementDefinition, clearAll, exportData, importData]);
  
  return (
    <DevContext.Provider value={value}>
      {children}
    </DevContext.Provider>
  );
}

export default DevProvider;
